create table dirkspzm32.cal_appointments (
    start_time                date not null enable,
    end_time                  date not null enable,
    appointment_id            varchar2(32 char) default sys_guid() not null enable,
    subject                   varchar2(255 char) not null enable,
    description               varchar2(4000 char),
    all_day                   varchar2(1 char) not null enable,
    location                  varchar2(255 char),
    status_id                 number(*, 0) not null enable,
    appointment_type_id       number(*, 0),
    calendar_id               varchar2(32 char) not null enable,
    recurrence_info_xml       clob,
    shared_resources_info_xml clob
);

alter table dirkspzm32.cal_appointments
    add constraint pk_cal_appointments primary key ( appointment_id )
        using index enable;


